import{_ as d,c as e,o as a,ag as r}from"./chunks/framework.Bw-5EFTY.js";const u=JSON.parse('{"title":"Android + Kotlin 知识点","description":"","frontmatter":{},"headers":[],"relativePath":"reading-notes/android/android-points.md","filePath":"reading-notes/android/android-points.md"}'),o={name:"reading-notes/android/android-points.md"};function h(i,t,n,c,l,b){return a(),e("div",null,t[0]||(t[0]=[r('<h1 id="android-kotlin-知识点" tabindex="-1">Android + Kotlin 知识点 <a class="header-anchor" href="#android-kotlin-知识点" aria-label="Permalink to &quot;Android + Kotlin 知识点&quot;">​</a></h1><p><a href="/reading-notes/android/android-points.en.html">English</a></p><p>知识点速查，按 Android 基础、进阶与 Kotlin 分类。</p><hr><h2 id="android-基础" tabindex="-1">Android 基础 <a class="header-anchor" href="#android-基础" aria-label="Permalink to &quot;Android 基础&quot;">​</a></h2><h3 id="手势与触控" tabindex="-1">手势与触控 <a class="header-anchor" href="#手势与触控" aria-label="Permalink to &quot;手势与触控&quot;">​</a></h3><table tabindex="0"><thead><tr><th>考点</th><th>答案</th></tr></thead><tbody><tr><td>双击手势</td><td><code>GestureDetector</code> + <code>SimpleOnGestureListener.onDoubleTap()</code>；不要手写时间间隔判断</td></tr><tr><td>多指数量判断</td><td><code>event.getPointerCount()</code></td></tr></tbody></table><h3 id="生命周期与可见性" tabindex="-1">生命周期与可见性 <a class="header-anchor" href="#生命周期与可见性" aria-label="Permalink to &quot;生命周期与可见性&quot;">​</a></h3><table tabindex="0"><thead><tr><th>考点</th><th>答案</th></tr></thead><tbody><tr><td>Activity 不可见时回调</td><td><code>onStop()</code></td></tr><tr><td>区分</td><td><code>onPause()</code> = 失去焦点但可能仍可见</td></tr></tbody></table><h3 id="存储与资源" tabindex="-1">存储与资源 <a class="header-anchor" href="#存储与资源" aria-label="Permalink to &quot;存储与资源&quot;">​</a></h3><table tabindex="0"><thead><tr><th>考点</th><th>答案</th></tr></thead><tbody><tr><td>SharedPreferences 保存</td><td>同步：<code>commit()</code>；异步：<code>apply()</code></td></tr><tr><td>多语言资源目录</td><td>如法语：<code>res/values-fr/strings.xml</code></td></tr><tr><td>Launcher 图标目录</td><td><code>mipmap</code></td></tr></tbody></table><h3 id="ui-与点击" tabindex="-1">UI 与点击 <a class="header-anchor" href="#ui-与点击" aria-label="Permalink to &quot;UI 与点击&quot;">​</a></h3><table tabindex="0"><thead><tr><th>考点</th><th>答案</th></tr></thead><tbody><tr><td>android:onClick 方法不存在</td><td>直接 crash → <code>IllegalStateException</code>（反射找不到方法）</td></tr><tr><td>播放视频的 View</td><td><code>VideoView</code>（不是 MediaPlayer / SurfaceView）</td></tr></tbody></table><h3 id="传感器" tabindex="-1">传感器 <a class="header-anchor" href="#传感器" aria-label="Permalink to &quot;传感器&quot;">​</a></h3><table tabindex="0"><thead><tr><th>考点</th><th>答案</th></tr></thead><tbody><tr><td>角速度</td><td><code>Sensor.TYPE_GYROSCOPE</code></td></tr><tr><td>空气温度</td><td><code>Sensor.TYPE_AMBIENT_TEMPERATURE</code></td></tr></tbody></table><h3 id="启动与进程" tabindex="-1">启动与进程 <a class="header-anchor" href="#启动与进程" aria-label="Permalink to &quot;启动与进程&quot;">​</a></h3><table tabindex="0"><thead><tr><th>考点</th><th>答案</th></tr></thead><tbody><tr><td>开机启动广播</td><td><code>android.intent.action.BOOT_COMPLETED</code>，需权限 <code>RECEIVE_BOOT_COMPLETED</code></td></tr><tr><td>FLAG_ACTIVITY_SINGLE_TOP</td><td>Activity 已在栈顶时不创建新实例，走 <code>onNewIntent()</code></td></tr><tr><td>进程优先级最高</td><td>Foreground process（最后被杀）</td></tr></tbody></table><hr><h2 id="android-进阶" tabindex="-1">Android 进阶 <a class="header-anchor" href="#android-进阶" aria-label="Permalink to &quot;Android 进阶&quot;">​</a></h2><h3 id="窗口特性" tabindex="-1">窗口特性 <a class="header-anchor" href="#窗口特性" aria-label="Permalink to &quot;窗口特性&quot;">​</a></h3><table tabindex="0"><thead><tr><th>考点</th><th>答案</th></tr></thead><tbody><tr><td>requestWindowFeature 有效常量</td><td><code>FEATURE_NO_TITLE</code>、<code>FEATURE_LEFT_ICON</code>、<code>FEATURE_RIGHT_ICON</code></td></tr><tr><td>无效常量</td><td><code>FEATURE_TOP_ICON</code>、<code>FEATURE_NO_ICON</code></td></tr></tbody></table><h3 id="触控与剪贴板" tabindex="-1">触控与剪贴板 <a class="header-anchor" href="#触控与剪贴板" aria-label="Permalink to &quot;触控与剪贴板&quot;">​</a></h3><table tabindex="0"><thead><tr><th>考点</th><th>答案</th></tr></thead><tbody><tr><td>MotionEvent 多点触控</td><td><code>ACTION_POINTER_DOWN</code> / <code>ACTION_POINTER_UP</code></td></tr><tr><td>剪贴板</td><td><code>ClipboardManager</code></td></tr><tr><td>拖拽接口</td><td><code>View.OnDragListener</code></td></tr></tbody></table><h3 id="相机与异常" tabindex="-1">相机与异常 <a class="header-anchor" href="#相机与异常" aria-label="Permalink to &quot;相机与异常&quot;">​</a></h3><table tabindex="0"><thead><tr><th>考点</th><th>答案</th></tr></thead><tbody><tr><td>Camera 被占用</td><td><code>openCamera</code> → <code>CameraAccessException</code></td></tr></tbody></table><h3 id="线程与异步" tabindex="-1">线程与异步 <a class="header-anchor" href="#线程与异步" aria-label="Permalink to &quot;线程与异步&quot;">​</a></h3><table tabindex="0"><thead><tr><th>考点</th><th>答案</th></tr></thead><tbody><tr><td>线程辅助类</td><td><code>ThreadPoolExecutor</code>、<code>HandlerThread</code>、<code>AsyncTask</code>（deprecated）、<code>AsyncTaskLoader</code></td></tr><tr><td>后台下载且旋转屏幕不终止</td><td>Service（通常前台服务）</td></tr></tbody></table><h3 id="其他" tabindex="-1">其他 <a class="header-anchor" href="#其他" aria-label="Permalink to &quot;其他&quot;">​</a></h3><table tabindex="0"><thead><tr><th>考点</th><th>答案</th></tr></thead><tbody><tr><td>RenderScript</td><td>高性能计算框架（图像/GPU），已废弃</td></tr></tbody></table><hr><h2 id="kotlin" tabindex="-1">Kotlin <a class="header-anchor" href="#kotlin" aria-label="Permalink to &quot;Kotlin&quot;">​</a></h2><h3 id="数字与字面量" tabindex="-1">数字与字面量 <a class="header-anchor" href="#数字与字面量" aria-label="Permalink to &quot;数字与字面量&quot;">​</a></h3><table tabindex="0"><thead><tr><th>考点</th><th>答案</th></tr></thead><tbody><tr><td>数字常量</td><td>支持 Decimal、Binary、Hex；<strong>不支持</strong> Octal</td></tr></tbody></table><h3 id="可见性修饰符" tabindex="-1">可见性修饰符 <a class="header-anchor" href="#可见性修饰符" aria-label="Permalink to &quot;可见性修饰符&quot;">​</a></h3><table tabindex="0"><thead><tr><th>考点</th><th>答案</th></tr></thead><tbody><tr><td>可见性（默认 public）</td><td><code>public</code>、<code>internal</code>、<code>protected</code>、<code>private</code></td></tr></tbody></table><h3 id="相等性" tabindex="-1">相等性 <a class="header-anchor" href="#相等性" aria-label="Permalink to &quot;相等性&quot;">​</a></h3><table tabindex="0"><thead><tr><th>考点</th><th>答案</th></tr></thead><tbody><tr><td>== vs ===</td><td><code>==</code> 内容相等（equals）；<code>===</code> 引用相等</td></tr></tbody></table><h3 id="sequence" tabindex="-1">Sequence <a class="header-anchor" href="#sequence" aria-label="Permalink to &quot;Sequence&quot;">​</a></h3><table tabindex="0"><thead><tr><th>考点</th><th>答案</th></tr></thead><tbody><tr><td>Sequence 特点</td><td>惰性计算（lazy）、无中间集合、支持 stateless/stateful operations</td></tr></tbody></table><h3 id="编译器参数" tabindex="-1">编译器参数 <a class="header-anchor" href="#编译器参数" aria-label="Permalink to &quot;编译器参数&quot;">​</a></h3><table tabindex="0"><thead><tr><th>考点</th><th>答案</th></tr></thead><tbody><tr><td>有效参数</td><td><code>-progressive</code>、<code>-Werror</code>、<code>-g</code></td></tr><tr><td>无效参数</td><td><code>-ver</code></td></tr></tbody></table>',41)]))}const q=d(o,[["render",h]]);export{u as __pageData,q as default};
